DELETE FROM task_status_history
WHERE id >= 'f4200000-0000-0000-0002-000000000001'
  AND id <= 'f4200000-0000-0000-0002-000000000099';

UPDATE tasks SET column_id = 'd0010000-0000-0000-0002-000000000004'::uuid
WHERE id = 'e1000000-0000-0000-0002-000000000043';
UPDATE tasks SET column_id = 'd0010000-0000-0000-0002-000000000002'::uuid
WHERE id IN (
    'e1000000-0000-0000-0002-000000000047',
    'e1000000-0000-0000-0002-000000000048'
);
